detaileddescription.para:
Different Marker Decoders will produce different data. Use this structure to find what the data structure is. switch(data->type){
caseMLMarkerTrackingDecodedDataType_Aruco:
MLMarkerTrackerDecodedArucoData*aruco=reinterpret_cast<MLMarkerTrackerDecodedArucoData*>(data);
MLog(Verbose,"ReceivedArucoCode%u",aruco->id);
break;
default:
MLog(Verbose,"Unhandledtypereceived");
}
